from __future__ import annotations

import heapq


def merge_sorted_iterators(iterators, source_weights=None):
    iterators = [iter(item) for item in iterators]
    weights = source_weights or list(range(len(iterators)))
    heap = []
    for idx, iterator in enumerate(iterators):
        try:
            value = next(iterator)
            heapq.heappush(heap, (value, weights[idx], idx))
        except StopIteration:
            pass
    while heap:
        value, _weight, idx = heapq.heappop(heap)
        yield value
        try:
            next_value = next(iterators[idx])
            heapq.heappush(heap, (next_value, weights[idx], idx))
        except StopIteration:
            pass

