from __future__ import annotations

import heapq


def merge_sorted_iterators(iterators):
    active = []
    iterators = [iter(item) for item in iterators]
    for idx, iterator in enumerate(iterators):
        try:
            active.append((next(iterator), idx))
        except StopIteration:
            pass
    heapq.heapify(active)
    while active:
        value, idx = heapq.heappop(active)
        yield value
        try:
            heapq.heappush(active, (next(iterators[idx]), idx))
        except StopIteration:
            continue

